import{_ as a,o as d,c as i,a2 as l}from"./chunks/framework.BWuWLRhz.js";const c=JSON.parse('{"title":"FlowMindLab / Obsidian 个人知识库","description":"","frontmatter":{},"headers":[],"relativePath":"projects/knowledge-tools/flowmindlab-quartz.md","filePath":"projects/knowledge-tools/flowmindlab-quartz.md"}'),n={name:"projects/knowledge-tools/flowmindlab-quartz.md"};function r(e,t,o,s,h,p){return d(),i("div",null,[...t[0]||(t[0]=[l(`<h1 id="flowmindlab-obsidian-个人知识库" tabindex="-1">FlowMindLab / Obsidian 个人知识库 <a class="header-anchor" href="#flowmindlab-obsidian-个人知识库" aria-label="Permalink to &quot;FlowMindLab / Obsidian 个人知识库&quot;">​</a></h1><blockquote><p>FlowMindLab 是我的 Obsidian 个人知识库和长期学习系统，线上站点为 <a href="https://www.flowmindlab.cn/" target="_blank" rel="noreferrer">flowmindlab.cn</a>。它以 Obsidian 仓库作为内容源，通过 Quartz 技术发布为公开知识站，目前主要整理 <span class="text-highlight-blue">知识管理、AI、机器学习、Python、MySQL、紫微斗数</span> 等内容，未来会继续把机器学习等应用场景写成自己的理解和实践心得。</p></blockquote><div class="project-snapshot"><div><strong>Obsidian</strong><span>本地长期知识库、个人记录和主题笔记管理</span></div><div><strong>5 类 MOC</strong><span>AI / 机器学习、MySQL、Python、知识管理、紫微斗数</span></div><div><strong>22 个内容文件</strong><span>当前公开站内容层的页面和主题入口</span></div><div><strong>flowmindlab.cn</strong><span>已上线的公开知识站入口</span></div></div><h2 id="项目定位" tabindex="-1">项目定位 <a class="header-anchor" href="#项目定位" aria-label="Permalink to &quot;项目定位&quot;">​</a></h2><p>FlowMindLab 是一张持续生长的个人知识地图。它的核心首先是 Obsidian 仓库中的知识库内容，Quartz 负责把这套 Markdown 知识结构发布成可访问的网站。</p><p>博客更适合发布完成度较高的文章，但我的很多内容处在持续学习和持续迭代中：知识管理方法、个人记录、AI 工具使用、机器学习理解、Python 自动化、MySQL 工作语法、Obsidian 方法、紫微斗数系统化学习等。如果只用普通文章结构，很难表达主题之间的关联。</p><p>所以我选择用 Obsidian 管理本地知识仓库，用 Quartz 将适合公开的部分发布为网页，让个人学习、项目复盘、长期记录和作品集形成连接。</p><h2 id="项目背景" tabindex="-1">项目背景 <a class="header-anchor" href="#项目背景" aria-label="Permalink to &quot;项目背景&quot;">​</a></h2><p>我长期需要处理几类信息：</p><ul><li>工作中沉淀的数据产品方法、SQL、BI、项目复盘。</li><li>AI 和编程学习过程中的工具、概念和实践。</li><li>紫微斗数、传统文化和 AI 解读系统相关知识。</li><li>个人项目、简历网站、证券考试工具等过程文档。</li><li>个人记录、阶段复盘和可以公开展示的长期能力证据。</li></ul><p>如果这些内容只留在本地，外部看不到；如果全部写成文章，又会丢失知识之间的连接。FlowMindLab 的目标，是在“个人笔记”和“公开作品”之间搭一座桥。</p><h2 id="项目目标" tabindex="-1">项目目标 <a class="header-anchor" href="#项目目标" aria-label="Permalink to &quot;项目目标&quot;">​</a></h2><ol><li>建立一个长期可维护的个人知识库。</li><li>用 MOC 和双链组织主题，减少笔记散落。</li><li>将部分学习内容和项目过程发布为公开网页。</li><li>与简历网站形成互补：简历网站展示项目结果，知识库展示长期学习、个人记录和思考过程。</li><li>让知识管理、AI、机器学习、数据产品、紫微斗数等长期方向有统一入口。</li><li>未来持续补充机器学习等应用场景的学习心得和实践理解。</li></ol><h2 id="我做了什么" tabindex="-1">我做了什么 <a class="header-anchor" href="#我做了什么" aria-label="Permalink to &quot;我做了什么&quot;">​</a></h2><table tabindex="0"><thead><tr><th>工作方向</th><th>具体工作</th></tr></thead><tbody><tr><td>站点搭建</td><td>使用 Quartz 4 将 Obsidian 仓库中适合公开的内容发布为 Markdown 知识站，并完成上线</td></tr><tr><td>内容结构</td><td>设计首页、关于我、知识地图、主题笔记、个人记录、学习资源和工作流入口</td></tr><tr><td>MOC 设计</td><td>建立 AI / 机器学习、MySQL、Python、知识管理、紫微斗数等主题地图</td></tr><tr><td>知识管理</td><td>使用 Obsidian 维护本地笔记，通过双链和目录组织内容</td></tr><tr><td>发布筛选</td><td>区分本地私有笔记和可公开内容，让知识库既能沉淀也能展示</td></tr><tr><td>与作品集连接</td><td>将知识库定位为简历网站之外的长期能力证明</td></tr></tbody></table><h2 id="站点结构" tabindex="-1">站点结构 <a class="header-anchor" href="#站点结构" aria-label="Permalink to &quot;站点结构&quot;">​</a></h2><p>当前公开内容层包括几个主要入口：</p><table tabindex="0"><thead><tr><th>模块</th><th>作用</th></tr></thead><tbody><tr><td>Home</td><td>个人主页与知识地图入口</td></tr><tr><td>About</td><td>介绍个人方向和长期关注主题</td></tr><tr><td>MOCs</td><td>各类主题地图总览</td></tr><tr><td>Notes</td><td>主题笔记和个人记录入口</td></tr><tr><td>Resources</td><td>学习资料库</td></tr><tr><td>Workflows</td><td>知识管理工作流</td></tr></tbody></table><p>首页中明确了几个长期主题：</p><ul><li>AI / 机器学习</li><li>MySQL</li><li>Python</li><li>知识管理</li><li>紫微斗数</li></ul><p>这些主题和我的简历项目之间是互相支撑的：AI 和知识管理支撑紫微斗数数据化解读系统，MySQL 和数据产品经验支撑利多星与澜思项目，Python 和自动化能力支撑证券考试工具和资料处理。后续机器学习相关内容会更偏个人理解和应用场景复盘，减少资料堆砌。</p><h2 id="moc-与知识地图" tabindex="-1">MOC 与知识地图 <a class="header-anchor" href="#moc-与知识地图" aria-label="Permalink to &quot;MOC 与知识地图&quot;">​</a></h2><p>FlowMindLab 的重点在于通过 MOC 组织入口，让主题之间形成可导航关系。</p><table tabindex="0"><thead><tr><th>MOC</th><th>内容方向</th><th>价值</th></tr></thead><tbody><tr><td>AI / 机器学习 MOC</td><td>AI 工具、模型理解、学习笔记、应用场景和实践记录</td><td>支撑 AI 产品、自动化能力和后续机器学习心得输出</td></tr><tr><td>MySQL MOC</td><td>工作中常用 SQL、查询场景和数据处理方法</td><td>支撑数据产品和 BI 分析</td></tr><tr><td>Python MOC</td><td>自动化脚本、数据处理、工具搭建</td><td>支撑个人项目和效率工具</td></tr><tr><td>知识管理 MOC</td><td>Obsidian、Quartz、笔记生命周期、发布流程</td><td>支撑长期知识系统</td></tr><tr><td>紫微斗数 MOC</td><td>紫微知识、规则、AI 解读系统相关内容</td><td>支撑紫微 AI 项目</td></tr></tbody></table><p>MOC 的作用，是让访问者从主题入口进入知识，避免陷入零散笔记。</p><h2 id="工作流设计" tabindex="-1">工作流设计 <a class="header-anchor" href="#工作流设计" aria-label="Permalink to &quot;工作流设计&quot;">​</a></h2><p>知识库里还沉淀了几个工作流页面：</p><table tabindex="0"><thead><tr><th>工作流</th><th>作用</th></tr></thead><tbody><tr><td>note-lifecycle</td><td>管理一条笔记从捕捉、整理、链接到发布的过程</td></tr><tr><td>obsidian-capture-workflow</td><td>管理日常输入、资料收集和初步整理</td></tr><tr><td>quartz-publishing-checklist</td><td>管理公开发布前的检查流程</td></tr></tbody></table><p>这些工作流让知识库同时呈现结果和维护过程。</p><h2 id="数据如何驱动" tabindex="-1">数据如何驱动 <a class="header-anchor" href="#数据如何驱动" aria-label="Permalink to &quot;数据如何驱动&quot;">​</a></h2><p>FlowMindLab 里的“数据”指知识节点和链接关系。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>学习资料 / 项目过程</span></span>
<span class="line"><span>  -&gt; Markdown 笔记</span></span>
<span class="line"><span>  -&gt; 标签 / 双链 / MOC</span></span>
<span class="line"><span>  -&gt; 公开知识站</span></span>
<span class="line"><span>  -&gt; 长期检索与复用</span></span></code></pre></div><p>数据驱动体现在：</p><ul><li>用目录和 MOC 控制知识入口。</li><li>用双链表达概念之间的关系。</li><li>用资源库区分资料和个人理解。</li><li>用工作流保证内容从收集到发布有稳定过程。</li><li>用公开站点让学习资产变成可被访问的能力证明。</li></ul><h2 id="成果与价值" tabindex="-1">成果与价值 <a class="header-anchor" href="#成果与价值" aria-label="Permalink to &quot;成果与价值&quot;">​</a></h2><ul><li>建立了基于 Obsidian 仓库的个人知识库，并通过 Quartz 技术发布为公开知识站：<a href="https://www.flowmindlab.cn/" target="_blank" rel="noreferrer">www.flowmindlab.cn</a>。</li><li>搭建首页、MOC、主题笔记、资源库和工作流等公开内容结构。</li><li>将知识管理、AI、Python、MySQL、机器学习和紫微斗数放入统一知识地图。</li><li>让个人学习过程、项目沉淀和简历作品集之间形成长期连接。</li><li>展示了我在 Markdown 内容管理、知识架构和个人系统搭建上的能力。</li></ul><h2 id="个人能力沉淀" tabindex="-1">个人能力沉淀 <a class="header-anchor" href="#个人能力沉淀" aria-label="Permalink to &quot;个人能力沉淀&quot;">​</a></h2><p>FlowMindLab 对我来说是长期学习和个人记录的基础设施。它让我把“学过什么、做过什么、怎么思考、如何复用”沉淀下来，也让我能把个人能力从一次性项目扩展为可持续生长的知识系统。</p>`,38)])])}const u=a(n,[["render",r]]);export{c as __pageData,u as default};
